import React from 'react';
import './AlertPanel.css';

const AlertPanel = ({ alerts, onAcknowledge, onResolve }) => {
  if (!alerts || alerts.length === 0) {
    return (
      <div className="alert-panel">
        <h3>Active Alerts</h3>
        <p className="no-alerts">✓ No active alerts</p>
      </div>
    );
  }

  const groupedAlerts = {
    CRITICAL: alerts.filter(a => a.severity === 'CRITICAL'),
    WARNING: alerts.filter(a => a.severity === 'WARNING'),
    INFO: alerts.filter(a => a.severity === 'INFO'),
  };

  return (
    <div className="alert-panel">
      <h3>Active Alerts ({alerts.length})</h3>

      {groupedAlerts.CRITICAL.length > 0 && (
        <div className="alert-group">
          <h4 className="group-title critical">🚨 Critical ({groupedAlerts.CRITICAL.length})</h4>
          {groupedAlerts.CRITICAL.map(alert => renderAlert(alert, onAcknowledge, onResolve))}
        </div>
      )}

      {groupedAlerts.WARNING.length > 0 && (
        <div className="alert-group">
          <h4 className="group-title warning">⚠️ Warning ({groupedAlerts.WARNING.length})</h4>
          {groupedAlerts.WARNING.map(alert => renderAlert(alert, onAcknowledge, onResolve))}
        </div>
      )}

      {groupedAlerts.INFO.length > 0 && (
        <div className="alert-group">
          <h4 className="group-title info">ℹ️ Information ({groupedAlerts.INFO.length})</h4>
          {groupedAlerts.INFO.map(alert => renderAlert(alert, onAcknowledge, onResolve))}
        </div>
      )}
    </div>
  );
};

const renderAlert = (alert, onAcknowledge, onResolve) => (
  <div key={alert.id} className={`alert-item ${alert.severity.toLowerCase()}`}>
    <div className="alert-header">
      <div className="alert-title">
        <span className="alert-type">{alert.alert_type}</span>
        <span className="alert-machine">{alert.machine_id}</span>
      </div>
      <div className="alert-time">
        {new Date(alert.triggered_at).toLocaleTimeString()}
      </div>
    </div>

    <div className="alert-message">{alert.title}</div>
    <div className="alert-description">{alert.description}</div>

    {alert.recommended_action && (
      <div className="alert-recommendation">
        <strong>Action:</strong> {alert.recommended_action}
      </div>
    )}

    <div className="alert-status">
      <span className={`status-badge ${alert.status.toLowerCase()}`}>
        {alert.status}
      </span>
    </div>

    <div className="alert-actions">
      {alert.status === 'OPEN' && (
        <>
          <button
            className="action-btn acknowledge"
            onClick={() => onAcknowledge && onAcknowledge(alert.id)}
          >
            Acknowledge
          </button>
          <button
            className="action-btn resolve"
            onClick={() => onResolve && onResolve(alert.id)}
          >
            Resolve
          </button>
        </>
      )}
      {alert.status === 'ACKNOWLEDGED' && (
        <button
          className="action-btn resolve"
          onClick={() => onResolve && onResolve(alert.id)}
        >
          Resolve
        </button>
      )}
    </div>
  </div>
);

export default AlertPanel;
